sql:
SELECT AVG(anxiety_score) AS average_anxiety_score
FROM anxiety_assessments
WHERE assessment_type = 'Post-treatment';

SELECT COUNT(*) AS diabetes_patient_count
FROM severity_records
WHERE condition = 'Diabetes';

SELECT AVG(severity_score) AS average_severity
FROM severity_records
WHERE condition = 'Asthma';

SELECT patient_id, condition
FROM severity_records
WHERE severity_score > 50;

SELECT patient_id, MAX(severity_score) AS max_severity_score
FROM severity_records
GROUP BY patient_id;

SELECT satisfaction_score
FROM satisfaction_surveys
WHERE patient_id = 1;

external_knowledge:
- 'Low satisfaction ratings' are considered to be less than 70 out of 100; 
- 'Received treatments in January 2023' refers to treatments administered between '2023-01-01' and '2023-01-31'; 
- 'Over 30' refers to patients with an age greater than 30.

